class TOTPAuthenticator:
    def __init__(self):
        self.totp = None
        
    def generate_secret(self):
        """Generate a new TOTP secret"""
        return pyotp.random_base32()
    
    def create_qr_code(self, secret, username, issuer):
        """Create QR code for authenticator app"""
        totp_uri = pyotp.totp.TOTP(secret).provisioning_uri(
            username, issuer_name=issuer
        )
        
        qr = qrcode.QRCode(version=1, box_size=10, border=4)
        qr.add_data(totp_uri)
        qr.make(fit=True)
        
        img = qr.make_image(fill_color="black", back_color="white")
        return img
    
    def validate_code(self, secret, code, valid_window=1):
        """Validate TOTP code against the secret"""
        totp = pyotp.TOTP(secret)
        return totp.verify(code, valid_window=valid_window)
    
    def get_current_code(self, secret):
        """Get current TOTP code"""
        totp = pyotp.TOTP(secret)
        return totp.now()
    
    def get_time_remaining(self, secret):
        """Get time remaining until code expires"""
        totp = pyotp.TOTP(secret)
        return 30 - (int(time.time()) % 30)

